import type { PointsConfig } from '@smartcart/shared-types';
import type { SessionItem } from '../entities/shopping-session.entity';
import type { IPointsCalculationStrategy } from './points-calculation-strategy.interface';

/**
 * WEEKEND_BONUS — `basePoints * quantity * (isWeekend ? weekendMultiplier : 1)`
 * (README §2.3 Strategy Types). The clock is injectable for deterministic tests.
 */
export class WeekendBonusStrategy implements IPointsCalculationStrategy {
  readonly strategyType = 'WEEKEND_BONUS' as const;

  constructor(private readonly now: () => Date = () => new Date()) {}

  calculate(item: SessionItem, config: PointsConfig): number {
    if (config.type !== 'WEEKEND_BONUS') {
      throw new Error('WeekendBonusStrategy received a non-WEEKEND_BONUS config');
    }
    const day = this.now().getUTCDay(); // 0 = Sunday, 6 = Saturday
    const isWeekend = day === 0 || day === 6;
    const multiplier = isWeekend ? config.weekendMultiplier : 1;
    return Math.round(config.basePoints * item.quantity * multiplier);
  }
}
